import React, { useState, useEffect } from 'react';
import './AdminDashboard.css';
import App from './App';
import { db } from './services/databaseService';

const AdminDashboard: React.FC = () => {
  const [currentTab, setCurrentTab] = useState('telemetry');
  const [logs, setLogs] = useState<any[]>([]);
  const [logsLoading, setLogsLoading] = useState(false);

  // Load logs on mount
  useEffect(() => {
    const loadLogs = async () => {
      const allLogs = await db.getLogs(50);
      setLogs(allLogs);
    };
    loadLogs();
  }, []);

  // Refresh logs when tab changes
  useEffect(() => {
    if (currentTab === 'logs') {
      refreshLogs();
    }
  }, [currentTab]);

  const refreshLogs = async () => {
    setLogsLoading(true);
    try {
      const updatedLogs = await db.getLogs(50);
      setLogs(updatedLogs);
    } finally {
      setLogsLoading(false);
    }
  };

  const clearLogs = async () => {
    if (window.confirm('Delete all logs?')) {
      await db.clearLogs();
      setLogs([]);
    }
  };

  return (
    <div className="admin-dashboard">
      <header className="admin-header">
        <h1>🛡️ Admin Dashboard</h1>
        <button className="logout-btn" onClick={() => window.close()}>
          Close
        </button>
      </header>

      <main className="admin-main">
        <sidebar className="admin-sidebar">
          <nav className="admin-nav">
            <button
              className={`nav-btn ${currentTab === 'telemetry' ? 'active' : ''}`}
              onClick={() => setCurrentTab('telemetry')}
            >
              📊 Telemetry
            </button>
            <button
              className={`nav-btn ${currentTab === 'analytics' ? 'active' : ''}`}
              onClick={() => setCurrentTab('analytics')}
            >
              📈 Analytics
            </button>
            <button
              className={`nav-btn ${currentTab === 'logs' ? 'active' : ''}`}
              onClick={() => setCurrentTab('logs')}
            >
              📋 Logs
            </button>
          </nav>
        </sidebar>

        <div className="admin-content">
          {/* Telemetry Tab */}
          {currentTab === 'telemetry' && (
            <div className="admin-section">
              <h2>Real-Time Telemetry Viewer</h2>
              <p className="desc">Live behavioral signals and bot detection analysis</p>
              <div className="telemetry-viewer">
                <App />
              </div>
            </div>
          )}

          {/* Analytics Tab */}
          {currentTab === 'analytics' && (
            <div className="admin-section">
              <h2>Analytics Dashboard</h2>
              <p className="desc">Bot detection statistics</p>

              <div className="stats-grid">
                <div className="stat-card">
                  <h3>Total Sessions</h3>
                  <p className="stat-value">{logs.length}</p>
                </div>

                <div className="stat-card">
                  <h3>Humans Detected</h3>
                  <p className="stat-value">
                    {logs.filter(l => l.level === 'SUCCESS').length}
                  </p>
                </div>

                <div className="stat-card">
                  <h3>Bots Blocked</h3>
                  <p className="stat-value">
                    {logs.filter(l => l.level === 'WARNING').length}
                  </p>
                </div>

                <div className="stat-card">
                  <h3>Success Rate</h3>
                  <p className="stat-value">
                    {logs.length > 0
                      ? Math.round((logs.filter(l => l.level === 'SUCCESS').length / logs.length) * 100)
                      : 0}%
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Logs Tab */}
          {currentTab === 'logs' && (
            <div className="admin-section">
              <h2>System Logs</h2>
              <p className="desc">Activity history and events</p>

              <div className="logs-header">
                <button className="action-btn" onClick={refreshLogs} disabled={logsLoading}>
                  {logsLoading ? '⏳' : '🔄'} Refresh
                </button>
                <button className="action-btn danger" onClick={clearLogs}>
                  🗑️ Clear
                </button>
                <span className="log-count">{logs.length} entries</span>
              </div>

              <div className="logs-container">
                {logs.length === 0 ? (
                  <p className="no-logs">No logs yet</p>
                ) : (
                  logs.map((log, idx) => (
                    <div key={idx} className={`log-entry log-${log.level?.toLowerCase()}`}>
                      <span className="log-time">{log.time}</span>
                      <span className="log-msg">{log.message}</span>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
